#ifndef GOOGLE_PROTOBUF_COMPILER_RUST_RUST_FIELD_TYPE_H__
#define GOOGLE_PROTOBUF_COMPILER_RUST_RUST_FIELD_TYPE_H__

#include "google/protobuf/descriptor.h"

namespace google {
namespace protobuf {
namespace compiler {
namespace rust {

// An enum of all of the singular types as they should be seen by Rust. This
// is parallel to FieldDescriptor::CppType with the main difference being that
// that String and Bytes are treated as different types.
enum class RustFieldType {
  INT32,
  INT64,
  UINT32,
  UINT64,
  DOUBLE,
  FLOAT,
  BOOL,
  ENUM,
  STRING,
  BYTES,
  MESSAGE,
};

// Note: for 'repeated X field' this returns the corresponding type of X.
// For map fields this returns MESSAGE.
RustFieldType GetRustFieldType(const FieldDescriptor& field);

RustFieldType GetRustFieldType(FieldDescriptor::Type type);

}  // namespace rust
}  // namespace compiler
}  // namespace protobuf
}  // namespace google

#endif  // GOOGLE_PROTOBUF_COMPILER_RUST_RUST_FIELD_TYPE_H__

#ifndef QPDF_OFFSETINPUTSOURCE_HH
#define QPDF_OFFSETINPUTSOURCE_HH

// This class implements an InputSource that proxies for an underlying input source but offset a
// specific number of bytes.

#include <qpdf/InputSource.hh>

class OffsetInputSource: public InputSource
{
  public:
    OffsetInputSource(std::shared_ptr<InputSource>, qpdf_offset_t global_offset);
    ~OffsetInputSource() override = default;

    qpdf_offset_t findAndSkipNextEOL() override;
    std::string const& getName() const override;
    qpdf_offset_t tell() override;
    void seek(qpdf_offset_t offset, int whence) override;
    void rewind() override;
    size_t read(char* buffer, size_t length) override;
    void unreadCh(char ch) override;

  private:
    std::shared_ptr<InputSource> proxied;
    qpdf_offset_t global_offset;
    qpdf_offset_t max_safe_offset;
};

#endif // QPDF_OFFSETINPUTSOURCE_HH

#ifndef PL_LZWDECODER_HH
#define PL_LZWDECODER_HH

#include <qpdf/Pipeline.hh>

#include <qpdf/Buffer.hh>
#include <vector>

class Pl_LZWDecoder final: public Pipeline
{
  public:
    Pl_LZWDecoder(char const* identifier, Pipeline* next, bool early_code_change);
    ~Pl_LZWDecoder() final = default;
    void write(unsigned char const* buf, size_t len) final;
    void finish() final;

  private:
    void sendNextCode();
    void handleCode(unsigned int code);
    unsigned char getFirstChar(unsigned int code);
    void addToTable(unsigned char next);

    // members used for converting bits to codes
    unsigned char buf[3]{0, 0, 0};
    unsigned int code_size{9};
    unsigned int next_char_{0};
    unsigned int byte_pos{0};
    unsigned int bit_pos{0}; // left to right: 01234567
    unsigned int bits_available{0};

    // members used for handle LZW decompression
    bool code_change_delta{false};
    bool eod{false};
    std::vector<Buffer> table;
    unsigned int last_code{256};
};

#endif // PL_LZWDECODER_HH

#include "google/protobuf/internal_feature_helper.h"

#include <string>

#include "absl/log/absl_check.h"
#include "absl/strings/escaping.h"
#include "absl/strings/string_view.h"
#include "google/protobuf/descriptor.h"
#include "google/protobuf/descriptor.pb.h"
#include "google/protobuf/extension_set.h"
#include "google/protobuf/feature_resolver.h"

namespace google {
namespace protobuf {
namespace internal {
FeatureSet InternalFeatureHelper::ParseAndGetEditionResolvedFeatureSet(
    absl::string_view data, Edition edition) {
  FeatureSetDefaults defaults;
  std::string unescaped_data;
  absl::Base64Unescape(data, &unescaped_data);
  ABSL_CHECK(defaults.ParseFromString(unescaped_data));
  auto edition_feature_set = GetEditionFeatureSetDefaults(edition, defaults);
  ABSL_CHECK_OK(edition_feature_set);
  return *edition_feature_set;
}
}  // namespace internal
}  // namespace protobuf
}  // namespace google
